<?php
if(session_status()===PHP_SESSION_NONE)session_start();if(empty($_SESSION['is_logged_in'])){header('Location: ../connexion.php');exit;}if(!in_array($_SESSION['user_type']??'', ['admin','gestionnaire'],true)){header('Location: dashboard.php');exit;}require_once __DIR__.'/../config/database.php';function qh($v):string{return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
foreach(fetchAll("SELECT id FROM tables WHERE supprimer=0 AND (qr_code_token IS NULL OR qr_code_token='')") as $missingQr){executeQuery('UPDATE tables SET qr_code_token=:token WHERE id=:id',[':token'=>bin2hex(random_bytes(16)),':id'=>$missingQr->id]);}
$tables=fetchAll('SELECT id,number,capacity,qr_code_token,status,is_active FROM tables WHERE supprimer=0 ORDER BY number');$base=(isset($_SERVER['HTTPS'])&&$_SERVER['HTTPS']!=='off'?'https':'http').'://'.($_SERVER['HTTP_HOST']??'localhost').rtrim(dirname(dirname($_SERVER['SCRIPT_NAME']??'/restaurant_issale/views/qrcodes.php')),'/');$name=trim(($_SESSION['user_nom']??'Utilisateur').' '.($_SESSION['user_prenom']??''));$initials=strtoupper(substr($_SESSION['user_nom']??'U',0,1).substr($_SESSION['user_prenom']??'',0,1));
?>
<!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>QR Codes — ISSALE</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Outfit:wght@600;700&display=swap" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css" rel="stylesheet"><script src="https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js"></script><style>
:root{--p:#8B1A1A;--pd:#5C0E0E;--gold:#D4A373;--bg:#FDF8F3;--side:#1A120E;--text:#1A120E;--muted:#83766f;--border:#eadfd5;--red:#c0392b;--font:'Inter',sans-serif;--display:'Outfit',sans-serif}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:var(--font)}.sidebar{position:fixed;inset:0 auto 0 0;width:256px;padding:24px;background:var(--side);display:flex;flex-direction:column;z-index:20}.brand{display:flex;gap:12px;align-items:center;margin-bottom:34px;color:#fff}.logo{width:42px;height:42px;border-radius:12px;background:linear-gradient(135deg,var(--p),var(--pd));display:grid;place-items:center}.brand h1{font:700 18px var(--display);margin:0}.brand small{color:var(--gold)}nav{display:grid;gap:5px}.label{color:#887d78;font-size:10px;font-weight:700;letter-spacing:.12em;margin:16px 12px 6px}.nav{display:flex;align-items:center;gap:12px;padding:11px 13px;color:#bdb5b1;text-decoration:none;border-radius:11px;font-size:14px}.nav:hover{color:#fff;background:#ffffff12}.nav.active{background:var(--gold);color:#1A120E;font-weight:700}.user{margin-top:auto;padding-top:18px;border-top:1px solid #ffffff14;display:flex;gap:10px;align-items:center;color:#fff}.avatar{width:38px;height:38px;border-radius:11px;background:#ffffff12;color:var(--gold);display:grid;place-items:center;font-weight:700}.user p{margin:0;font-size:13px;font-weight:600}.user span{font-size:11px;color:#918783}.logout{margin-left:auto;color:#aaa}.main{margin-left:256px}.top{position:sticky;top:0;z-index:10;padding:17px 30px;background:#fdf8f3e8;backdrop-filter:blur(12px);border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center}.top h2{font:700 23px var(--display);margin:0}.top small{color:var(--muted)}.menu-btn{display:none;border:0;background:none;font-size:24px}.content{padding:30px}.crumb{font-size:13px;color:var(--muted);margin-bottom:20px}.crumb a{color:var(--p);text-decoration:none}.toolbar{display:flex;justify-content:space-between;gap:15px;margin-bottom:20px}.search{position:relative;max-width:380px;flex:1}.search i{position:absolute;left:14px;top:13px;color:#a39790}.search input{width:100%;padding:12px 14px 12px 40px;border:1px solid var(--border);border-radius:11px;background:#fff;font:14px var(--font)}.btn{border:0;border-radius:10px;padding:10px 13px;font:600 12px var(--font);cursor:pointer;display:inline-flex;align-items:center;gap:7px}.primary{background:var(--p);color:#fff}.light{background:#f4ede7;color:var(--text)}.qr-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:18px}.qr-card{background:#fff;border:1px solid var(--border);border-radius:18px;padding:22px;text-align:center;transition:.2s}.qr-card:hover{transform:translateY(-3px);box-shadow:0 8px 25px #1a120e12}.qr-card h3{font:700 18px var(--display);margin:13px 0 4px}.qr-card p{font-size:12px;color:var(--muted);margin:0 0 15px}.qr-box{width:190px;height:190px;margin:auto;padding:10px;background:#fff;border:1px solid var(--border);border-radius:14px;display:grid;place-items:center}.qr-box img,.qr-box canvas{max-width:100%;height:auto}.actions{display:flex;justify-content:center;flex-wrap:wrap;gap:7px}.status{display:inline-block;padding:4px 8px;border-radius:99px;font-size:10px;font-weight:700;background:#e8f5ec;color:#2d7d46}.inactive{background:#eee;color:#666}.empty{text-align:center;background:#fff;border:1px solid var(--border);border-radius:18px;padding:60px;color:var(--muted)}.overlay{position:fixed;inset:0;background:#1a120e88;display:none;align-items:center;justify-content:center;padding:20px;z-index:100}.overlay.open{display:flex}.modal{width:min(430px,100%);background:#fff;border-radius:20px}.head{display:flex;justify-content:space-between;padding:22px 24px;border-bottom:1px solid var(--border)}.head h3{font:700 19px var(--display);margin:0}.close{border:0;background:none;font-size:23px}.body{padding:24px;text-align:center}.foot{display:flex;justify-content:flex-end;gap:9px;padding:18px 24px;border-top:1px solid var(--border)}.toast{position:fixed;right:22px;bottom:22px;background:#1A120E;color:#fff;padding:14px 18px;border-radius:11px;z-index:200}.mobile-overlay{display:none}@media(max-width:768px){.sidebar{transform:translateX(-100%);transition:.2s}.sidebar.open{transform:none}.mobile-overlay.open{display:block;position:fixed;inset:0;background:#0006;z-index:15}.main{margin-left:0}.menu-btn{display:block}.content{padding:20px 16px}.toolbar{flex-direction:column}}@media print{.sidebar,.top,.crumb,.toolbar,.actions{display:none!important}.main{margin:0}.content{padding:0}.qr-grid{grid-template-columns:repeat(2,1fr)}.qr-card{break-inside:avoid;border:1px solid #ddd;box-shadow:none}}
</style></head><body><aside class="sidebar" id="sidebar"><div class="brand"><div class="logo"><i class="bi bi-cup-hot-fill"></i></div><div><h1>ISSALE</h1><small>Administration</small></div></div><nav><div class="label">Menu</div><a class="nav" href="dashboard.php"><i class="bi bi-grid-1x2"></i>Tableau de bord</a><a class="nav" href="menus.php"><i class="bi bi-journal-richtext"></i>Menus</a><a class="nav" href="categories.php"><i class="bi bi-tags"></i>Catégories</a><a class="nav" href="tables.php"><i class="bi bi-grid-3x3-gap"></i>Tables</a><a class="nav active" href="qrcodes.php"><i class="bi bi-qr-code"></i>QR Codes</a><?php if(($_SESSION['user_type']??'')==='admin'):?><a class="nav" href="utilisateurs.php"><i class="bi bi-people"></i>Utilisateurs</a><?php endif;?></nav><div class="user"><div class="avatar"><?=qh($initials)?></div><div><p><?=qh($name)?></p><span><?=qh(ucfirst($_SESSION['user_type']??''))?></span></div><a class="logout" href="../models/logout.php"><i class="bi bi-box-arrow-right"></i></a></div></aside><div class="mobile-overlay" id="mobileOverlay" onclick="toggleSidebar()"></div>
<main class="main"><header class="top"><div style="display:flex;align-items:center;gap:12px"><button class="menu-btn" onclick="toggleSidebar()"><i class="bi bi-list"></i></button><div><h2>QR Codes des tables</h2><small>Accès rapide au menu client</small></div></div><span><?=count($tables)?> QR code(s)</span></header><section class="content"><div class="crumb"><a href="dashboard.php">Tableau de bord</a> &nbsp;/&nbsp; QR Codes</div><div class="toolbar"><div class="search"><i class="bi bi-search"></i><input id="search" oninput="filterQr()" placeholder="Rechercher une table…"></div><button class="btn primary" onclick="window.print()"><i class="bi bi-printer"></i>Imprimer tous</button></div>
<?php if(!$tables):?><div class="empty"><i class="bi bi-qr-code" style="font-size:42px"></i><p>Aucune table disponible pour générer un QR code.</p><a href="tables.php">Créer une table</a></div><?php else:?><div class="qr-grid"><?php foreach($tables as $t):$url=$base.'/menu.php?table='.rawurlencode($t->number).'&token='.rawurlencode($t->qr_code_token);?><article class="qr-card" data-search="<?=qh(strtolower($t->number))?>"><div class="qr-box" id="qr-<?=$t->id?>" data-url="<?=qh($url)?>"></div><h3>Table <?=qh($t->number)?></h3><p><?=$t->capacity?> places · <span class="status <?=$t->is_active?'':'inactive'?>"><?=$t->is_active?'Active':'Inactive'?></span></p><div class="actions"><button class="btn light" onclick="downloadQr(<?=$t->id?>,<?=qh(json_encode($t->number))?>)"><i class="bi bi-download"></i>Télécharger</button><button class="btn light" onclick="printQr(<?=$t->id?>,<?=qh(json_encode($t->number))?>)"><i class="bi bi-printer"></i>Imprimer</button><button class="btn light" title="Régénérer" onclick="askRegenerate(<?=$t->id?>,<?=qh(json_encode($t->number))?>)"><i class="bi bi-arrow-clockwise"></i></button></div></article><?php endforeach;?></div><?php endif;?></section></main>
<div class="overlay" id="regenerateModal"><div class="modal"><div class="head"><h3>Régénérer le QR code</h3><button class="close" onclick="closeRegenerate()">×</button></div><div class="body"><div style="font-size:28px;color:var(--p)"><i class="bi bi-arrow-clockwise"></i></div><p>Régénérer le QR code de la table <strong id="regenerateName"></strong> ?</p><small style="color:var(--red)">L'ancien QR code ne fonctionnera plus.</small></div><div class="foot"><button class="btn light" onclick="closeRegenerate()">Annuler</button><button class="btn primary" id="regenerateBtn" onclick="executeRegenerate()">Régénérer</button></div></div></div>
<script>
document.querySelectorAll('.qr-box').forEach(el=>new QRCode(el,{text:el.dataset.url,width:168,height:168,colorDark:'#1A120E',colorLight:'#ffffff',correctLevel:QRCode.CorrectLevel.H}));function toggleSidebar(){sidebar.classList.toggle('open');mobileOverlay.classList.toggle('open')}function filterQr(){const q=search.value.toLowerCase();document.querySelectorAll('.qr-card').forEach(c=>c.style.display=!q||c.dataset.search.includes(q)?'':'none')}function qrImage(id){const box=document.getElementById('qr-'+id);return box.querySelector('canvas')?.toDataURL('image/png')||box.querySelector('img')?.src}function downloadQr(id,name){const a=document.createElement('a');a.href=qrImage(id);a.download='QR-Table-'+name+'.png';a.click()}function printQr(id,name){const src=qrImage(id),w=open('','_blank');w.document.write(`<title>QR Table ${name}</title><div style="text-align:center;font-family:sans-serif"><h2>ISSALE Restaurant</h2><img src="${src}" width="280"><h1>Table ${name}</h1><p>Scannez pour consulter le menu</p></div>`);w.document.close();w.onload=()=>w.print()}
let regenerateId=null;function askRegenerate(id,name){regenerateId=id;regenerateName.textContent=name;regenerateModal.classList.add('open')}function closeRegenerate(){regenerateModal.classList.remove('open');regenerateId=null}async function executeRegenerate(){if(!regenerateId)return;regenerateBtn.disabled=true;try{const r=await fetch('../models/traitement/tables-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'regenerate',id:regenerateId})}),o=await r.json();toast(o.message);if(o.success)setTimeout(()=>location.reload(),600)}catch(e){toast('Une erreur est survenue.')}finally{regenerateBtn.disabled=false}}function toast(msg){document.querySelector('.toast')?.remove();const t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.append(t);setTimeout(()=>t.remove(),3500)}regenerateModal.onclick=e=>{if(e.target===regenerateModal)closeRegenerate()};
</script><script src="../assets/js/sidebar-sync.js"></script></body></html>
